```

**현재 Service (Before) - N+1 발생 지점**

```kotlin
// application/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val userRepository: UserRepository,   // 문제: 별도 userRepository 주입
    private val profileRepository: ProfileRepository, // 문제: 또 다른 별도 조회
) {
    fun getFollowingList(followerId: String): List<FollowDto> {
        // 쿼리 1: follow 목록 조회 (1회)
        val follows = followRepository.findByFollowerId(followerId)

        return follows.map { follow ->
            // 문제: N+1 - follow 개수만큼 user 조회 반복 (N회)
            val user = userRepository.findById(follow.followingId).orElseThrow()
            // 문제: N+1 - follow 개수만큼 profile 조회 반복 (N회)
            val profile = profileRepository.findByUserId(follow.followingId)

            FollowDto(
                userId = user.id,
                nickname = user.nickname,
                profileImageUrl = profile?.imageUrl,
                followedAt = follow.createdAt,
            )
        }
    }
}
